import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaPrint, FaSpinner, FaFileWord, 
  FaFilePowerpoint, FaFileImage, FaFileArchive, FaFilter 
} from 'react-icons/fa';
import config from '../config/config';
import { getSubjectDetails, getMaterialsForSubject, downloadMaterial } from '../services/api';
import './MaterialsPage.css';

const MaterialsPage = () => {
  const { programId, branchId, semester, subjectId } = useParams();
  const navigate = useNavigate();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [stats, setStats] = useState({
    total: 0,
    byType: {}
  });

  // Material types with icons and colors
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: <FaFilter />, color: '#6B7280' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'imp_questions', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'books', name: 'Books', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignments', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' },
    { id: 'lab_manual', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#8B5CF6' }
  ];

  // Get file icon based on file type
  const getFileIcon = (fileType) => {
    if (!fileType) return <FaFileAlt />;
    
    const type = fileType.toLowerCase();
    if (type.includes('pdf')) return <FaFilePdf className="text-red-500" />;
    if (type.includes('doc')) return <FaFileWord className="text-blue-500" />;
    if (type.includes('ppt') || type.includes('powerpoint')) return <FaFilePowerpoint className="text-orange-500" />;
    if (type.includes('image') || type.includes('jpg') || type.includes('png') || type.includes('jpeg')) return <FaFileImage className="text-green-500" />;
    if (type.includes('zip') || type.includes('rar')) return <FaFileArchive className="text-purple-500" />;
    return <FaFileAlt className="text-gray-500" />;
  };

  // Format file size
  const formatFileSize = (bytes) => {
    if (!bytes) return 'N/A';
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  // Fetch subject and materials data
  useEffect(() => {
    fetchData();
  }, [subjectId]);

  const fetchData = async () => {
    try {
      setLoading(true);
      
      // Fetch subject details
      const subjectData = await getSubjectDetails(subjectId);
      setSubject(subjectData.subject);
      
      // Fetch materials
      const materialsData = await getMaterialsForSubject(subjectId);
      console.log('Materials data:', materialsData);
      
      if (materialsData.notes && Array.isArray(materialsData.notes)) {
        const transformedMaterials = materialsData.notes.map(note => ({
          id: note.id,
          title: note.title || 'Untitled',
          type: note.material_type || 'notes',
          description: note.description || 'No description available',
          fileSize: formatFileSize(note.file_size),
          fileSizeBytes: note.file_size,
          fileType: note.file_type || 'pdf',
          pages: note.pages || 0,
          uploadDate: note.uploaded_at ? new Date(note.uploaded_at).toLocaleDateString() : 'N/A',
          downloads: note.downloads || 0,
          views: note.views || 0,
          rating: 4.5,
          fileUrl: `${config.API_BASE_URL}/notes/${note.id}/download`,
          originalFileName: note.original_filename || `${note.title}.${note.file_type || 'pdf'}`,
          user: note.user_name || 'Unknown',
          status: note.status || 'approved',
          subjectName: note.subject_name || 'Unknown',
          branchName: note.branch_name || 'Unknown',
          programName: note.program_name || 'Unknown'
        }));
        
        setMaterials(transformedMaterials);
        
        // Calculate stats
        const statsData = {
          total: transformedMaterials.length,
          byType: {}
        };
        
        materialTypes.forEach(type => {
          if (type.id !== 'all') {
            statsData.byType[type.id] = transformedMaterials.filter(m => m.type === type.id).length;
          }
        });
        
        setStats(statsData);
      } else {
        console.warn('No materials found or invalid response');
        setMaterials([]);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
      // Fallback to mock data if API fails
      setMaterials(getMockMaterials());
      setStats({
        total: 8,
        byType: {
          notes: 3,
          pyq: 2,
          syllabus: 1,
          imp_questions: 1,
          books: 1
        }
      });
    } finally {
      setLoading(false);
    }
  };

  // Mock data fallback
  const getMockMaterials = () => {
    return [
      {
        id: 1,
        title: 'Complete Syllabus 2024',
        type: 'syllabus',
        description: 'Official syllabus with unit-wise distribution',
        fileSize: '1.2 MB',
        fileSizeBytes: 1258291,
        fileType: 'pdf',
        pages: 12,
        uploadDate: '2024-01-15',
        downloads: 245,
        views: 500,
        rating: 4.5,
        fileUrl: '#',
        originalFileName: 'syllabus_2024.pdf',
        user: 'Admin',
        status: 'approved'
      },
      {
        id: 2,
        title: 'Data Structures Complete Notes',
        type: 'notes',
        description: 'Handwritten notes with diagrams and examples',
        fileSize: '4.5 MB',
        fileSizeBytes: 4718592,
        fileType: 'pdf',
        pages: 45,
        uploadDate: '2024-01-20',
        downloads: 420,
        views: 800,
        rating: 4.8,
        fileUrl: '#',
        originalFileName: 'ds_notes.pdf',
        user: 'Student',
        status: 'approved'
      },
      {
        id: 3,
        title: 'PYQ 2020-2023',
        type: 'pyq',
        description: 'Previous year questions with solutions',
        fileSize: '3.2 MB',
        fileSizeBytes: 3355443,
        fileType: 'pdf',
        pages: 35,
        uploadDate: '2024-01-05',
        downloads: 520,
        views: 1000,
        rating: 4.9,
        fileUrl: '#',
        originalFileName: 'pyq_2020_2023.pdf',
        user: 'Admin',
        status: 'approved'
      },
      {
        id: 4,
        title: 'Important Questions Set 1',
        type: 'imp_questions',
        description: 'Most expected questions for exams',
        fileSize: '1.5 MB',
        fileSizeBytes: 1572864,
        fileType: 'pdf',
        pages: 18,
        uploadDate: '2024-01-22',
        downloads: 380,
        views: 600,
        rating: 4.4,
        fileUrl: '#',
        originalFileName: 'imp_questions_set1.pdf',
        user: 'Faculty',
        status: 'approved'
      }
    ];
  };

  // Handle back navigation
  const handleBack = () => {
    navigate(`/program/${programId}/branch/${branchId}/semester/${semester}`);
  };

  // Handle download
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      if (!material.fileUrl || material.fileUrl === '#') {
        // Create dummy download for mock data
        const blob = new Blob(['This is a dummy file for testing'], { type: 'text/plain' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${material.title.replace(/\s+/g, '_')}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
        
        // Update download count in UI
        setMaterials(prev => prev.map(m => 
          m.id === material.id 
            ? { ...m, downloads: m.downloads + 1 } 
            : m
        ));
        
        setTimeout(() => {
          setDownloading(prev => ({ ...prev, [material.id]: false }));
        }, 1000);
        return;
      }
      
      // Real download from backend
      const response = await fetch(material.fileUrl, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      
      if (response.ok) {
        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = material.originalFileName || `${material.title.replace(/\s+/g, '_')}.${material.fileType}`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
        
        // Update download count in UI
        setMaterials(prev => prev.map(m => 
          m.id === material.id 
            ? { ...m, downloads: m.downloads + 1 } 
            : m
        ));
        
        console.log(`✅ Downloaded: ${material.title}`);
      } else {
        throw new Error('Download failed');
      }
    } catch (error) {
      console.error('Download error:', error);
      alert('❌ Download failed. Please try again.');
    } finally {
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };

  // Handle preview
  const handlePreview = (material) => {
    if (!material.fileUrl || material.fileUrl === '#') {
      alert(`Preview not available for: ${material.title}\nThis is a demo file.`);
      return;
    }
    
    // Open in new tab for PDFs
    if (material.fileType === 'pdf') {
      window.open(material.fileUrl, '_blank');
    } else {
      // For other file types, try to open in browser or download
      window.open(material.fileUrl, '_blank');
    }
  };

  // Filter materials based on selected type and search query
  const filteredMaterials = materials.filter(material => {
    const matchesType = selectedType === 'all' || material.type === selectedType;
    const matchesSearch = searchQuery === '' || 
      material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      material.description.toLowerCase().includes(searchQuery.toLowerCase());
    
    return matchesType && matchesSearch;
  });

  // Get type info
  const getTypeInfo = (typeId) => {
    return materialTypes.find(t => t.id === typeId) || materialTypes[0];
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
        <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-blue-500 mb-4"></div>
        <p className="text-gray-600 text-lg">Loading study materials...</p>
        <p className="text-gray-400 text-sm mt-2">Please wait while we fetch your materials</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-4 md:p-6">
      <div className="max-w-7xl mx-auto">
        {/* Back Button */}
        <button
          onClick={handleBack}
          className="flex items-center gap-2 px-4 py-2 mb-6 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors duration-200 shadow-md"
        >
          <FaArrowLeft />
          Back to Subjects
        </button>

        {/* Subject Header */}
        <div className="bg-white rounded-2xl shadow-lg p-6 mb-8">
          <div className="flex flex-col md:flex-row md:items-center gap-6">
            <div className="flex-shrink-0">
              <div className="w-20 h-20 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
                <span className="text-3xl text-white">📚</span>
              </div>
            </div>
            
            <div className="flex-1">
              <h1 className="text-3xl font-bold text-gray-800 mb-2">
                {subject?.name || 'Subject Name'}
              </h1>
              <p className="text-gray-600 mb-3">
                Code: <span className="font-semibold">{subject?.code || 'SUB101'}</span> • 
                Credits: <span className="font-semibold">{subject?.credits || 3}</span> • 
                Semester: <span className="font-semibold">{semester}</span>
              </p>
              
              <div className="flex flex-wrap items-center gap-2 text-sm text-gray-500">
                <span>Program: <span className="font-medium">{subject?.program_name || 'B.Tech'}</span></span>
                <span>•</span>
                <span>Branch: <span className="font-medium">{subject?.branch_name || 'CSE'}</span></span>
                <span>•</span>
                <span>Total Materials: <span className="font-medium">{stats.total}</span></span>
              </div>
              
              {subject?.description && (
                <p className="mt-4 text-gray-700 bg-blue-50 p-3 rounded-lg">
                  {subject.description}
                </p>
              )}
            </div>
            
            <div className="flex-shrink-0">
              <div className="bg-blue-50 rounded-lg p-4 text-center">
                <div className="text-2xl font-bold text-blue-600">{stats.total}</div>
                <div className="text-sm text-gray-600">Total Files</div>
              </div>
            </div>
          </div>
        </div>

        {/* Search Bar */}
        <div className="bg-white rounded-xl shadow-md p-4 mb-6">
          <div className="relative">
            <input
              type="text"
              placeholder="Search materials by title or description..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full px-4 py-3 pl-12 bg-gray-50 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
            <div className="absolute left-4 top-3.5 text-gray-400">
              🔍
            </div>
            {searchQuery && (
              <button
                onClick={() => setSearchQuery('')}
                className="absolute right-4 top-3.5 text-gray-400 hover:text-gray-600"
              >
                ✕
              </button>
            )}
          </div>
        </div>

        {/* Material Type Filter */}
        <div className="bg-white rounded-xl shadow-md p-6 mb-8">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Filter by Material Type</h3>
          <div className="flex flex-wrap gap-3">
            {materialTypes.map(type => (
              <button
                key={type.id}
                onClick={() => setSelectedType(type.id)}
                className={`flex items-center gap-2 px-4 py-3 rounded-lg transition-all duration-200 ${
                  selectedType === type.id
                    ? 'ring-2 ring-opacity-50 transform scale-105'
                    : 'hover:bg-gray-50'
                }`}
                style={{
                  backgroundColor: selectedType === type.id ? `${type.color}15` : 'transparent',
                  borderLeft: `4px solid ${type.color}`,
                  color: selectedType === type.id ? type.color : '#4B5563'
                }}
              >
                <span>{type.icon}</span>
                <span className="font-medium">{type.name}</span>
                {type.id !== 'all' && (
                  <span className="bg-gray-100 text-gray-600 text-xs font-medium px-2 py-1 rounded-full ml-2">
                    {stats.byType[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Materials Grid */}
        <div className="bg-white rounded-xl shadow-md p-6 mb-8">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-xl font-bold text-gray-800">
              {selectedType === 'all' ? 'All Study Materials' : getTypeInfo(selectedType).name}
              <span className="text-gray-500 font-normal ml-2">
                ({filteredMaterials.length} {filteredMaterials.length === 1 ? 'file' : 'files'})
              </span>
            </h3>
            
            <div className="flex items-center gap-4 text-sm text-gray-600">
              <div className="hidden md:flex items-center gap-2">
                <span className="text-green-500">●</span>
                <span>Notes ({stats.byType.notes || 0})</span>
              </div>
              <div className="hidden md:flex items-center gap-2">
                <span className="text-purple-500">●</span>
                <span>PYQs ({stats.byType.pyq || 0})</span>
              </div>
            </div>
          </div>

          {filteredMaterials.length === 0 ? (
            <div className="text-center py-16">
              <div className="text-6xl mb-4">📭</div>
              <h3 className="text-xl font-semibold text-gray-700 mb-2">No materials found!</h3>
              <p className="text-gray-500 mb-6">
                {searchQuery 
                  ? `No materials match "${searchQuery}"`
                  : 'No materials available for this subject yet.'
                }
              </p>
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="px-4 py-2 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200 transition-colors"
                >
                  Clear Search
                </button>
              )}
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredMaterials.map(material => {
                const typeInfo = getTypeInfo(material.type);
                
                return (
                  <div
                    key={material.id}
                    className="border border-gray-200 rounded-xl overflow-hidden hover:shadow-lg transition-all duration-300 bg-white group"
                  >
                    {/* Material Header */}
                    <div 
                      className="p-4 border-b border-gray-100 flex justify-between items-center"
                      style={{ backgroundColor: `${typeInfo.color}10` }}
                    >
                      <div className="flex items-center gap-2">
                        <span style={{ color: typeInfo.color }}>
                          {typeInfo.icon}
                        </span>
                        <span 
                          className="font-medium text-sm"
                          style={{ color: typeInfo.color }}
                        >
                          {typeInfo.name}
                        </span>
                      </div>
                      
                      {material.status === 'pending' && (
                        <span className="text-xs bg-yellow-100 text-yellow-800 px-2 py-1 rounded-full">
                          Pending Approval
                        </span>
                      )}
                    </div>

                    {/* Material Content */}
                    <div className="p-5">
                      <div className="flex items-start gap-3 mb-3">
                        <div className="flex-shrink-0 mt-1">
                          {getFileIcon(material.fileType)}
                        </div>
                        <div>
                          <h4 className="font-bold text-gray-800 mb-2 line-clamp-2">
                            {material.title}
                          </h4>
                          <p className="text-gray-600 text-sm mb-4 line-clamp-3">
                            {material.description}
                          </p>
                        </div>
                      </div>

                      {/* Material Stats */}
                      <div className="grid grid-cols-2 gap-3 mb-4 text-xs text-gray-500">
                        <div className="flex items-center gap-1">
                          <FaClock className="text-gray-400" />
                          <span>{material.uploadDate}</span>
                        </div>
                        <div className="flex items-center gap-1">
                          <FaDownload className="text-gray-400" />
                          <span>{material.downloads} downloads</span>
                        </div>
                        <div className="flex items-center gap-1">
                          <FaEye className="text-gray-400" />
                          <span>{material.views} views</span>
                        </div>
                        <div className="flex items-center gap-1">
                          {getFileIcon(material.fileType)}
                          <span>{material.fileSize}</span>
                        </div>
                      </div>

                      {/* Uploader Info */}
                      <div className="flex items-center justify-between text-xs text-gray-500 border-t border-gray-100 pt-3">
                        <span className="flex items-center gap-1">
                          👤 <span>Uploaded by: {material.user}</span>
                        </span>
                        {material.pages > 0 && (
                          <span className="flex items-center gap-1">
                            📖 <span>{material.pages} pages</span>
                          </span>
                        )}
                      </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="p-4 bg-gray-50 border-t border-gray-100 flex gap-2">
                      <button
                        onClick={() => handlePreview(material)}
                        className="flex-1 px-4 py-2.5 bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors duration-200 flex items-center justify-center gap-2"
                      >
                        <FaEye />
                        <span className="hidden sm:inline">Preview</span>
                      </button>
                      
                      <button
                        onClick={() => handleDownload(material)}
                        disabled={downloading[material.id]}
                        className="flex-1 px-4 py-2.5 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg hover:from-green-600 hover:to-emerald-700 transition-all duration-200 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                        style={{ minWidth: '120px' }}
                      >
                        {downloading[material.id] ? (
                          <>
                            <FaSpinner className="animate-spin" />
                            <span className="hidden sm:inline">Downloading...</span>
                          </>
                        ) : (
                          <>
                            <FaDownload />
                            <span className="hidden sm:inline">Download</span>
                          </>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Quick Stats */}
        <div className="bg-white rounded-xl shadow-md p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-6 flex items-center gap-2">
            📊 Material Statistics
          </h3>
          
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-4">
            {materialTypes.slice(1).map(type => (
              <div
                key={type.id}
                className="text-center p-4 rounded-lg border border-gray-100 hover:border-gray-200 transition-colors"
                style={{ borderTop: `3px solid ${type.color}` }}
              >
                <div className="text-2xl font-bold mb-1" style={{ color: type.color }}>
                  {stats.byType[type.id] || 0}
                </div>
                <div className="text-sm text-gray-600">{type.name}</div>
              </div>
            ))}
          </div>
          
          <div className="mt-8 pt-6 border-t border-gray-100">
            <div className="flex flex-wrap justify-between items-center gap-4">
              <div>
                <p className="text-gray-700">
                  <span className="font-semibold">Total Downloads:</span>{' '}
                  {materials.reduce((sum, m) => sum + m.downloads, 0)}
                </p>
                <p className="text-gray-700">
                  <span className="font-semibold">Total Views:</span>{' '}
                  {materials.reduce((sum, m) => sum + m.views, 0)}
                </p>
              </div>
              
              <button
                onClick={() => window.print()}
                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors flex items-center gap-2"
              >
                <FaPrint />
                Print Summary
              </button>
            </div>
          </div>
        </div>

        {/* Footer Note */}
        <div className="mt-8 p-4 bg-blue-50 rounded-xl border border-blue-100">
          <p className="text-blue-800 text-sm">
            <span className="font-semibold">💡 Tip:</span>{' '}
            Download materials for offline study. All materials are regularly updated and 
            verified by our team. Need specific content?{' '}
            <button className="text-blue-600 hover:underline font-medium">
              Request via email
            </button>
          </p>
        </div>
      </div>
    </div>
  );
};

export default MaterialsPage;
